import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Phone, Lock, Globe } from 'lucide-react';

const translations = {
  en: { title: 'AGRICHAIN', subtitle: 'Farm Intelligence', phone: 'Phone Number', otp: 'Enter OTP', sendOtp: 'Send OTP', verify: 'Verify & Login', newUser: 'New User? Register' },
  hi: { title: 'एग्रीचेन', subtitle: 'कृषि बुद्धिमत्ता', phone: 'फोन नंबर', otp: 'OTP दर्ज करें', sendOtp: 'OTP भेजें', verify: 'सत्यापित करें', newUser: 'नए उपयोगकर्ता? पंजीकरण करें' },
  mr: { title: 'एग्रीचेन', subtitle: 'शेती बुद्धिमत्ता', phone: 'फोन नंबर', otp: 'OTP टाका', sendOtp: 'OTP पाठवा', verify: 'सत्यापित करा', newUser: 'नवीन वापरकर्ता? नोंदणी करा' }
};

function Login({ onLogin, language, setLanguage }) {
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [otpSent, setOtpSent] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const t = translations[language];

  const handleSendOtp = async () => {
    if (phone.length !== 10) {
      alert('Please enter valid 10-digit phone number');
      return;
    }
    setLoading(true);
    try {
      const res = await axios.post('/api/auth/send-otp', { phone });
      setOtpSent(true);
      alert(`OTP sent! (Dev: ${res.data.otp})`);
    } catch (error) {
      alert('Error sending OTP');
    }
    setLoading(false);
  };

  const handleVerify = async () => {
    setLoading(true);
    try {
      const res = await axios.post('/api/auth/verify-otp', { phone, otp });
      onLogin(res.data.user, res.data.token);
      if (!res.data.user.location) {
        navigate('/register');
      }
    } catch (error) {
      alert('Invalid OTP');
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="card max-w-md w-full">
        <div className="flex justify-end mb-4">
          <select value={language} onChange={(e) => setLanguage(e.target.value)} className="px-3 py-1 border rounded-lg">
            <option value="en">English</option>
            <option value="hi">हिंदी</option>
            <option value="mr">मराठी</option>
          </select>
        </div>

        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-green-600 mb-2">🌾 {t.title}</h1>
          <p className="text-gray-600 text-lg">{t.subtitle}</p>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-gray-700 font-semibold mb-2 text-lg">{t.phone}</label>
            <div className="relative">
              <Phone className="absolute left-3 top-4 text-gray-400" size={20} />
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                className="input-field pl-12"
                placeholder="9876543210"
                maxLength="10"
                disabled={otpSent}
              />
            </div>
          </div>

          {otpSent && (
            <div>
              <label className="block text-gray-700 font-semibold mb-2 text-lg">{t.otp}</label>
              <div className="relative">
                <Lock className="absolute left-3 top-4 text-gray-400" size={20} />
                <input
                  type="text"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                  className="input-field pl-12"
                  placeholder="123456"
                  maxLength="6"
                />
              </div>
            </div>
          )}

          {!otpSent ? (
            <button onClick={handleSendOtp} disabled={loading} className="btn-primary w-full text-xl">
              {loading ? '...' : t.sendOtp}
            </button>
          ) : (
            <button onClick={handleVerify} disabled={loading} className="btn-primary w-full text-xl">
              {loading ? '...' : t.verify}
            </button>
          )}

          <p className="text-center text-gray-600 mt-4">
            <button onClick={() => navigate('/register')} className="text-green-600 font-semibold">
              {t.newUser}
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
